    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    if file:
        filepath = os.path.join(app.root_path, 'uploads', file.filename)
        file.save(filepath)

        output_path = create_thumbnail_with_imagemagick(filepath)

        return jsonify({'output_path': output_path})

def create_thumbnail_with_imagemagick(input_filepath):
    output_filename = f"{os.path.splitext(os.path.basename(input_filepath))[0]}_thumbnail.{os.path.splitext(os.path.basename(input_filepath))[1]}"
    output_path = os.path.join(app.root_path, 'uploads', output_filename)

    subprocess.run(["convert", input_filepath, "-resize", "100x100", output_path])

    return output_path

if __name__ == '__main__':
    app.run()
